import { report } from '@/utils/index'

export enum Events {
  h5_loginpage = 'h5_loginpage',
  h5_loginpage_elementclick = 'h5_loginpage_elementclick',
  h5_phoneloginpage = 'h5_phoneloginpage',
  h5_login_detailpage_elementclick = 'h5_login_detailpage_elementclick',
  h5_verifycodeloginpage_verifycode = 'h5_verifycodeloginpage_verifycode',
  h5_loginpage_enpower_no_account_pop_show = 'h5_loginpage_enpower_no_account_pop_show',
  h5_loginpage_enpower_no_account_pop_click = 'h5_loginpage_enpower_no_account_pop_click',
  user_login_report_failed = 'user_login_report_failed',
}

export type EventMap = {
  [Events.h5_loginpage]: H5_LOGINPAGE
  [Events.h5_loginpage_elementclick]: H5_LOGINPAGE_ELEMENTCLICK
  [Events.h5_phoneloginpage]: H5_PHONELOGINPAGE
  [Events.h5_login_detailpage_elementclick]: H5_LOGIN_DETAILPAGE_ELEMENTCLICK
  [Events.h5_verifycodeloginpage_verifycode]: H5_VERIFYCODELOGINPAGE_VERIFYCODE
  [Events.h5_loginpage_enpower_no_account_pop_show]: H5_LOGINPAGE_ENPOWER_NO_ACCOUNT_POP_SHOW
  [Events.h5_loginpage_enpower_no_account_pop_click]: H5_LOGINPAGE_ENPOWER_NO_ACCOUNT_POP_CLICK
  [Events.user_login_report_failed]: user_login_report_failed
}

export type H5_LOGINPAGE = {
  is_first_time: boolean
}

export type H5_LOGINPAGE_ELEMENTCLICK = {
  element_name: string
}

export type H5_PHONELOGINPAGE = {
  source: string
}

export type H5_LOGIN_DETAILPAGE_ELEMENTCLICK = {
  source: string
  operation_type: string
  phone_str: string
  country_code_str: string
}

export type H5_VERIFYCODELOGINPAGE_VERIFYCODE = {
  country_code_str: string
  phone_str: string
  result: string
  error_message: string
}

export type H5_LOGINPAGE_ENPOWER_NO_ACCOUNT_POP_SHOW = {
  source: string
}

export type H5_LOGINPAGE_ENPOWER_NO_ACCOUNT_POP_CLICK = {
  source: string
  element_name: string
}

export function reportEvent<T extends keyof EventMap>(event: T, data: EventMap[T]) {
  report(event, data)
}

export enum ErrorReason {
  获取token失败 = '获取token失败',
  API失败 = 'API失败',
}

export type user_login_report_failed = {
  is_sawaapp_authorize: boolean
  source: 'sawa'
  type: '登录'
  error_code: string
  error_content: string
  h5_type: 'apple' | 'google' | 'facebook' | 'phone'
  h5_scene: 'login' | 'get_code' | 'get_token'
}
